"use client"

import { motion } from "framer-motion"
import { useInView } from "framer-motion"
import { useRef } from "react"
import { Leaf, ChefHat, Sparkles, Home } from "lucide-react"

const experiences = [
  {
    icon: Leaf,
    title: "Fresh Ingredients",
    description: "Premium quality sourced daily",
  },
  {
    icon: ChefHat,
    title: "Authentic Recipes",
    description: "Traditional methods perfected",
  },
  {
    icon: Sparkles,
    title: "Hygienic Kitchen",
    description: "Highest standards maintained",
  },
  {
    icon: Home,
    title: "Warm Ambience",
    description: "Comfortable family atmosphere",
  },
]

export default function ExperienceStrip() {
  const ref = useRef(null)
  const isInView = useInView(ref, { once: true, margin: "-100px" })

  return (
    <section ref={ref} className="border-y border-border bg-background py-20 px-4">
      <div className="mx-auto max-w-7xl">
        <div className="grid gap-12 md:grid-cols-2 lg:grid-cols-4">
          {experiences.map((experience, index) => (
            <motion.div
              key={experience.title}
              initial={{ opacity: 0, y: 20 }}
              animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
              transition={{ duration: 0.6, delay: index * 0.1 }}
              className="text-center"
            >
              <div className="mx-auto mb-6 flex h-16 w-16 items-center justify-center rounded-full bg-accent/10">
                <experience.icon className="h-8 w-8 text-accent" strokeWidth={1.5} />
              </div>
              <h3 className="mb-2 font-serif text-xl font-medium text-primary">{experience.title}</h3>
              <p className="text-sm text-foreground/70">{experience.description}</p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  )
}
